121	export async function getRegistriesConfig(
122	  cwd: string,
123	  options?: { useCache?: boolean }
124	) {
125	  const { useCache = true } = options || {}
126	
127	  // Clear cache if requested
128	  if (!useCache) {
129	    explorer.clearCaches()
130	  }
131	
132	  const configResult = await explorer.search(cwd)
133	
134	  if (!configResult) {
135	    // Do not throw an error if the config is missing.
136	    // We still have access to the built-in registries.
137	    return {
138	      registries: BUILTIN_REGISTRIES,
139	    }
140	  }
141	
142	  // Parse just the registries field from the config
143	  const registriesConfig = z
144	    .object({
145	      registries: registryConfigSchema.optional(),
146	    })
147	    .safeParse(configResult.config)
148	
149	  if (!registriesConfig.success) {
150	    throw new ConfigParseError(cwd, registriesConfig.error)
151	  }
152	
153	  // Merge built-in registries with user registries
154	  return {
155	    registries: {
156	      ...BUILTIN_REGISTRIES,
157	      ...(registriesConfig.data.registries || {}),
158	    },
159	  }
160	}
