209	/**
210	 * @deprecated This function is deprecated and will be removed in a future version.
211	 */
212	export async function resolveTree(
213	  index: z.infer<typeof registryIndexSchema>,
214	  names: string[]
215	) {
216	  const tree: z.infer<typeof registryIndexSchema> = []
217	
218	  for (const name of names) {
219	    const entry = index.find((entry) => entry.name === name)
220	
221	    if (!entry) {
222	      continue
223	    }
224	
225	    tree.push(entry)
226	
227	    if (entry.registryDependencies) {
228	      const dependencies = await resolveTree(index, entry.registryDependencies)
229	      tree.push(...dependencies)
230	    }
231	  }
232	
233	  return tree.filter(
234	    (component, index, self) =>
235	      self.findIndex((c) => c.name === component.name) === index
236	  )
237	}
238	
239	/**
240	 * @deprecated This function is deprecated and will be removed in a future version.
241	 */
242	export async function fetchTree(
243	  style: string,
244	  tree: z.infer<typeof registryIndexSchema>
245	) {
246	  try {
247	    const paths = tree.map((item) => `styles/${style}/${item.name}.json`)
248	    const results = await fetchRegistry(paths)
249	    return results.map((result) => registryItemSchema.parse(result))
250	  } catch (error) {
251	    handleError(error)
252	    return []
253	  }
254	}
255	
256	/**
257	 * @deprecated This function is deprecated and will be removed in a future version.
258	 */
259	export async function getItemTargetPath(
260	  config: Config,
261	  item: Pick<z.infer<typeof registryItemSchema>, "type">,
262	  override?: string
263	) {
264	  if (override) {
265	    return override
266	  }
267	
268	  if (item.type === "registry:ui") {
269	    return config.resolvedPaths.ui ?? config.resolvedPaths.components
270	  }
271	
272	  const [parent, type] = item.type?.split(":") ?? []
273	  if (!(parent in config.resolvedPaths)) {
274	    return null
275	  }
276	
277	  return path.join(
278	    config.resolvedPaths[parent as keyof typeof config.resolvedPaths],
279	    type
280	  )
281	}
