### `StepperItem` component

```tsx
function StepperItem({
  value,
  disabled = false,
  completed = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  disabled?: boolean
  completed?: boolean
}) {
  const { value: activeValue, orientation } = useStepper()
  const state = activeValue === value
    ? "active"
    : completed
    ? "completed"
    : "incomplete"

  return (
