"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    value: "step-1",
    title: "Your details",
    description: "Name and email",
    content:
      "Please provide your full name and email address so we can set up your account.",
  },
  {
    value: "step-2",
    title: "Company info",
    description: "Your company details",
    content:
      "Tell us about your company. This helps us tailor the experience to your needs.",
  },
  {
    value: "step-3",
    title: "Invite team",
    description: "Start collaborating",
    content:
      "Invite your teammates to join and start collaborating right away.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState("step-1")
  const [completedSteps, setCompletedSteps] = React.useState<string[]>([])

  const currentIndex = steps.findIndex((s) => s.value === activeStep)
  const isLastStep = currentIndex === steps.length - 1

  function handleNext() {
    if (!completedSteps.includes(activeStep)) {
      setCompletedSteps((prev) => [...prev, activeStep])
    }
    if (!isLastStep) {
      setActiveStep(steps[currentIndex + 1].value)
    }
  }

  function handleBack() {
    if (currentIndex > 0) {
      setActiveStep(steps[currentIndex - 1].value)
    }
  }

  function handleReset() {
    setActiveStep("step-1")
    setCompletedSteps([])
  }

  return (
    <div className="flex w-full max-w-2xl flex-col gap-12">
      {/* Horizontal stepper */}
      <div className="flex flex-col gap-4">
        <p className="text-muted-foreground text-xs font-medium uppercase tracking-wider">
          Horizontal
        </p>
        <Stepper
          value={activeStep}
          onValueChange={setActiveStep}
          orientation="horizontal"
        >
          <div className="flex w-full">
            {steps.map((step, index) => (
              <StepperItem
                key={step.value}
                value={step.value}
                completed={completedSteps.includes(step.value)}
              >
                <StepperTrigger>
                  <StepperIndicator>
                    {completedSteps.includes(step.value) ? (
                      <CheckIcon className="size-4" />
                    ) : (
                      index + 1
                    )}
                  </StepperIndicator>
                  <div className="flex flex-col gap-0.5">
                    <StepperTitle>{step.title}</StepperTitle>
                    <StepperDescription>{step.description}</StepperDescription>
                  </div>
                </StepperTrigger>
                {index < steps.length - 1 && <StepperSeparator />}
              </StepperItem>
            ))}
          </div>
          {steps.map((step) => (
            <StepperContent
              key={step.value}
              value={step.value}
              className="rounded-lg border p-6"
            >
              <p className="text-muted-foreground text-sm">{step.content}</p>
            </StepperContent>
          ))}
        </Stepper>

        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentIndex === 0}
          >
            Back
          </Button>
          {isLastStep ? (
            <Button onClick={handleReset}>Reset</Button>
          ) : (
            <Button onClick={handleNext}>Next</Button>
          )}
        </div>
      </div>

      {/* Vertical stepper */}
      <div className="flex flex-col gap-4">
        <p className="text-muted-foreground text-xs font-medium uppercase tracking-wider">
          Vertical
        </p>
        <Stepper
          value={activeStep}
          onValueChange={setActiveStep}
          orientation="vertical"
          className="gap-0"
        >
          {steps.map((step, index) => (
            <StepperItem
              key={step.value}
              value={step.value}
              completed={completedSteps.includes(step.value)}
            >
              <StepperTrigger>
                <StepperIndicator>
                  {completedSteps.includes(step.value) ? (
                    <CheckIcon className="size-4" />
                  ) : (
                    index + 1
                  )}
                </StepperIndicator>
                <div className="flex flex-col gap-0.5">
                  <StepperTitle>{step.title}</StepperTitle>
                  <StepperDescription>{step.description}</StepperDescription>
                </div>
              </StepperTrigger>
              {/* ms-11 = size-8 (32px) + gap-3 (12px) — aligns with label text */}
              <StepperContent className="text-muted-foreground ms-11 pb-4 text-sm">
                {step.content}
              </StepperContent>
              {index < steps.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </Stepper>
      </div>
    </div>
  )
}

