    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperIndicator
// ---------------------------------------------------------------------------

function StepperIndicator({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-indicator"
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
        // incomplete
        "group-data-[state=incomplete]/stepper-item:border-border group-data-[state=incomplete]/stepper-item:text-muted-foreground",
        // active
        "group-data-[state=active]/stepper-item:border-primary group-data-[state=active]/stepper-item:text-primary",
        // completed
        "group-data-[state=completed]/stepper-item:border-primary group-data-[state=completed]/stepper-item:bg-primary group-data-[state=completed]/stepper-item:text-primary-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "shrink-0 bg-border transition-colors",
        // completed: highlight the connector
        "group-data-[state=completed]/stepper-item:bg-primary",
        // horizontal: flex-1 horizontal rule inside the item's flex-row
        "group-data-[orientation=horizontal]/stepper-item:h-px group-data-[orientation=horizontal]/stepper-item:flex-1 group-data-[orientation=horizontal]/stepper-item:min-w-8",
        // vertical: short vertical connector centered under the indicator
        // size-8 indicator = 32px wide, center at 16px = ms-4
        "group-data-[orientation=vertical]/stepper-item:ms-4 group-data-[orientation=vertical]/stepper-item:mt-1 group-data-[orientation=vertical]/stepper-item:h-6 group-data-[orientation=vertical]/stepper-item:w-px",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent
// ---------------------------------------------------------------------------

function StepperContent({
  value: valueProp,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { value?: string }) {
  const { value: activeValue } = useStepper()
  const itemCtx = React.useContext(StepperItemContext)

  // Falls back to the enclosing StepperItem's value when no explicit value
  // is provided — handy for vertical layouts where content lives inside the item.
  const targetValue = valueProp ?? itemCtx?.value

  if (!targetValue || activeValue !== targetValue) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("text-sm", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

